{% extends "base.html" %}

{% block title %}Todo List{% endblock %}

{% block content %}
<h1>Welcome</h1>
<p>Keep track of what you need to do.</p>
<nav aria-label="Get started">
    <a href="/register" class="btn btn--primary">Create account</a>
    <a href="/login" class="btn btn--secondary">Sign in</a>
</nav>
{% endblock %}

